class MKAverage {
    private int m, k;
    private int[] stream;
    private int index;

    public MKAverage(int m, int k) {
        this.m = m;
        this.k = k;
        this.stream = new int[m];
        this.index = 0;
    }

    public void addElement(int num) {
        stream[index % m] = num;
        index++;
    }

    public int calculateMKAverage() {
        if (index < m) {
            return -1;
        }
        int[] lastM = new int[m];
        System.arraycopy(stream, (index - 1) % m + 1, lastM, 0, m - ((index - 1) % m + 1));
        System.arraycopy(stream, 0, lastM, m - ((index - 1) % m + 1), (index - 1) % m + 1);
        Arrays.sort(lastM);
        int sum = 0;
        for (int i = k; i < m - k; i++) {
            sum += lastM[i];
        }
        return sum / (m - 2 * k);
    }
}
